    public interface SessionStore {
        void save(AuthenticatedSession session);
        AuthenticatedSession get(String sessionId);
        void invalidate(String sessionId);
    }

    public static final class InMemorySessionStore implements SessionStore {
        private final Map<String, AuthenticatedSession> sessions = new ConcurrentHashMap<>();

        @Override
        public void save(AuthenticatedSession session) {
            sessions.put(session.getSessionId(), session);
        }

        @Override
        public AuthenticatedSession get(String sessionId) {
            AuthenticatedSession s = sessions.get(sessionId);
            if (s == null) return null;
            if (s.getExpiresAt() != null && !Clock.systemUTC().now().isBefore(s.getExpiresAt())) {
                sessions.remove(sessionId);
                return null;
            }
            return s;
        }

        @Override
        public void invalidate(String sessionId) {
            sessions.remove(sessionId);
        }
    }

    public interface Clock {
        Instant now();

        static Clock systemUTC() {
            return Instant::now;
        }
    }

